code.C:
#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int res = 1;
    for (int i = 0; i < n; i++) {
        int x;
        scanf("%d", &x);
        res *= x;
    }
    printf("%d\n", res);
    return 0;
}

